# Solution: Testing Error Handling

def expect_error(func, error_type, *args):
    """Return True if func(*args) raises error_type, False otherwise."""
    try:
        func(*args)
        return False
    except error_type:
        return True
    except Exception:
        return False

def expect_message(func, expected_msg, *args):
    """Return True if func(*args) raises an error whose message contains expected_msg."""
    try:
        func(*args)
        return False
    except Exception as e:
        return expected_msg in str(e)

def error_catalog(func, test_inputs):
    """Return dict mapping each input to the error type name (or "success")."""
    catalog = {}
    for inp in test_inputs:
        try:
            func(inp)
            catalog[inp] = "success"
        except Exception as e:
            catalog[inp] = type(e).__name__
    return catalog

def verify_handler(func, error_inputs, success_inputs):
    """Return dict with correctly_handled, incorrectly_handled, false_positive counts."""
    correctly_handled = 0
    incorrectly_handled = 0
    false_positive = 0
    for inp in error_inputs:
        try:
            func(inp)
            incorrectly_handled += 1
        except Exception:
            correctly_handled += 1
    for inp in success_inputs:
        try:
            func(inp)
        except Exception:
            false_positive += 1
    return {"correctly_handled": correctly_handled, "incorrectly_handled": incorrectly_handled, "false_positive": false_positive}

testCases.validation:
def bad():
    raise ValueError('invalid input')
assert expect_message(bad, 'invalid') == True

testCases.input:
def strict_int(x):
    if not isinstance(x, int):
        raise TypeError('not int')
    return x
verify_handler(strict_int, ['hello', 3.14], [1, 2])['correctly_handled']

